  return calls === 1;
})()

(function(){
  var chip = document.querySelectorAll('.chordChips .c')[1] || document.querySelector('.chordChips .c');
  if (!chip) return 'no chip found';
  var calls = 0;
  var origStrum = window.ChordAudio.strum, origTone = window.ChordAudio.tone;
  window.ChordAudio.strum = function(){ calls++; };
  window.ChordAudio.tone = function(){ calls++; };
  chip.focus();
  chip.click(); // native <button> Enter/Space activation dispatches click with no pointerdown
  window.ChordAudio.strum = origStrum; window.ChordAudio.tone = origTone;
  return calls === 1;
})()
